        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"Invalid file type. Allowed types for avatars: {string.Join(", ", AvatarExtensions)}"
            });
        }

        if (file.Length > MaxAvatarSize)
        {
