    private async Task<FileUploadResult> SaveFileAsync(IFormFile file, string subfolder, string extension)
    {
        try
        {
            var uploadsPath = Path.Combine(_environment.WebRootPath, "uploads", subfolder);

            if (!Directory.Exists(uploadsPath))
            {
                Directory.CreateDirectory(uploadsPath);
            }

            var safeFileName = $"{Guid.NewGuid()}{extension.ToLowerInvariant()}";
            var filePath = Path.Combine(uploadsPath, safeFileName);

            var fullPath = Path.GetFullPath(filePath);
            var expectedBasePath = Path.GetFullPath(uploadsPath);
            if (!fullPath.StartsWith(expectedBasePath, StringComparison.OrdinalIgnoreCase))
            {
                return new FileUploadResult
                {
                    Success = false,
                    ErrorMessage = "Invalid file path detected."
                };
            }

            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                await file.CopyToAsync(stream);
            }

            var relativePath = Path.Combine("uploads", subfolder, safeFileName).Replace("\\", "/");

            return new FileUploadResult
            {
                Success = true,
                FilePath = $"/{relativePath}",
                FileName = safeFileName,
                FileSize = file.Length
            };
        }
        catch (Exception ex)
        {
            return new FileUploadResult
            {
                Success = false,
                ErrorMessage = "An error occurred while saving the file."
            };
        }
    }

    private static async Task<bool> ValidateFileSignature(IFormFile file, string extension)
    {
        if (!FileSignatures.ContainsKey(extension))
        {
            // For extensions without known signatures (e.g., .svg), allow but rely on extension check
            return true;
        }

        var signatures = FileSignatures[extension];

        using var reader = new BinaryReader(file.OpenReadStream());
        var maxSignatureLength = signatures.Max(s => s.Length);
        var headerBytes = reader.ReadBytes(maxSignatureLength);

        if (headerBytes.Length < signatures.Min(s => s.Length))
        {
            return false;
        }

        return signatures.Any(signature =>
            headerBytes.Length >= signature.Length &&
            headerBytes.Take(signature.Length).SequenceEqual(signature));
    }

    private static string SanitizeFileName(string fileName)
    {
        if (string.IsNullOrWhiteSpace(fileName))
            return "unknown";

        var invalidChars = Path.GetInvalidFileNameChars();
        var sanitized = new string(fileName.Where(c => !invalidChars.Contains(c)).ToArray());

        if (sanitized.Length > 100)
            sanitized = sanitized[..100];

        return string.IsNullOrWhiteSpace(sanitized) ? "unknown" : sanitized;
    }
